body {
	--spectrum-font-family: var(--spectrum-sans-font-family-stack);
	--spectrum-font-style: var(--spectrum-default-font-style);
	--spectrum-font-size: var(--spectrum-font-size-100);

	margin: 0;

	font-family: var(--spectrum-font-family);
	font-size: var(--spectrum-font-size);
	font-style: var(--spectrum-font-style);

	color: var(--spectrum-neutral-content-color-default, rgb(34, 34, 34));
	background-color: var(--spectrum-background-base-color, rgb(230, 230, 230));
}

body {
	--spectrum-font-family-ar: myriad-arabic, adobe-clean, "Source Sans Pro", -apple-system, blinkmacsystemfont, "Segoe UI", roboto, ubuntu, "Trebuchet MS", "Lucida Grande", sans-serif;
	--spectrum-font-family-he: myriad-hebrew, adobe-clean, "Source Sans Pro", -apple-system, blinkmacsystemfont, "Segoe UI", roboto, ubuntu, "Trebuchet MS", "Lucida Grande", sans-serif;

	--spectrum-font-family: var(--spectrum-sans-font-family-stack);
	--spectrum-font-style: var(--spectrum-default-font-style);
	--spectrum-font-size: var(--spectrum-font-size-100);

	margin: 0;

	font-family: var(--spectrum-font-family);
	font-size: var(--spectrum-font-size);
	font-style: var(--spectrum-font-style);
}

button[data-action="collapse-root"] {
	font-family: var(--spectrum-sans-font-family-stack);
	font-style: var(--spectrum-detail-sans-serif-font-style);
	font-weight: var(--spectrum-detail-sans-serif-font-weight);
	font-size: var(--spectrum-detail-size-m);
	margin-block-start: 0;
	margin-block-end: 0;

	color: var(--spectrum-detail-color);

	line-height: var(--spectrum-detail-line-height);
	letter-spacing: var(--spectrum-detail-letter-spacing);
	text-transform: uppercase;
}

&:hover {
	color: var(--mod-accordion-item-header-color-hover, var(--spectrum-accordion-item-header-color-hover));
	background-color: var(--mod-accordion-background-color-hover, var(--spectrum-accordion-background-color-hover));

	+ .spectrum-Accordion-itemIconContainer {
		color: var(--mod-accordion-item-header-color-hover, var(--spectrum-accordion-item-header-color-hover));
	}
}

&:focus-visible {
	border-radius: var(--mod-accordion-corner-radius, var(--spectrum-accordion-corner-radius));

	outline: var(--mod-accordion-focus-indicator-thickness, var(--spectrum-accordion-focus-indicator-thickness)) solid var(--mod-accordion-focus-indicator-color, var(--spectrum-accordion-focus-indicator-color));
	background-color: var(--mod-accordion-background-color-key-focus, var(--spectrum-accordion-background-color-key-focus));
	color: var(--mod-accordion-item-header-color-key-focus, var(--spectrum-accordion-item-header-color-key-focus));
	outline-offset: calc(var(--mod-accordion-focus-indicator-gap, var(--spectrum-accordion-focus-indicator-gap)) * -1);
}

&::after {
	position: absolute;
	inset: 0;

	margin: calc((var(--spectrum-actionbutton-focus-indicator-gap) + var(--spectrum-actionbutton-border-width)) * -1);

	border-radius: var(--mod-actionbutton-focus-indicator-border-radius, calc(var(--spectrum-actionbutton-border-radius) + var(--spectrum-actionbutton-focus-indicator-gap)));

	transition: box-shadow var(--mod-actionbutton-animation-duration, var(--spectrum-animation-duration-100)) ease-in-out;

	pointer-events: none;
	content: "";
}

&::before {
	content: "";

	position: absolute;
	inset: calc(-1 * var(--mod-assetcard-focus-ring-gap, var(--spectrum-assetcard-focus-ring-gap)));

	border: var(--mod-assetcard-focus-indicator-thickness, var(--spectrum-assetcard-focus-indicator-thickness)) solid var(--mod-assectcard-focus-indicator-color, var(--spectrum-assestcard-focus-indicator-color));

	border-radius: var(--mod-assetcard-focus-ring-border-radius, var(--spectrum-assetcard-focus-ring-border-radius));

	opacity: 0;
	pointer-events: none;
	transition: opacity var(--mod-assetcard-asset-animation-duration, var(--spectrum-assetcard-asset-animation-duration)) ease-in-out;
}

&::after {
	content: "";
	position: absolute;
	inset: 0;
	z-index: 3;

	border: var(--mod-assetcard-asset-container-border-size, var(--spectrum-assetcard-asset-container-border-size)) solid var(--mod-assetcard-border-color, var(--spectrum-assetcard-border-color));
	border-radius: calc(var(--mod-assetcard-border-radius, var(--spectrum-assetcard-border-radius)) - 1px);
}

&.is-selected {
	background-color: var(--highcontrast-assetlist-item-background-color-selected, var(--mod-assetlist-item-background-color-selected, var(--spectrum-assetlist-item-background-color-selected)));

	&:hover,
	&:focus {
		background-color: var(--highcontrast-assetlist-item-background-color-selected-hover, var(--mod-assetlist-item-background-color-selected-hover, var(--spectrum-assetlist-item-background-color-selected-hover)));
	}
}

&:last-of-type {
	font-family: var(--mod-breadcrumbs-font-family-current, var(--spectrum-breadcrumbs-font-family-current));
	font-size: var(--mod-breadcrumbs-font-size-current, var(--spectrum-breadcrumbs-font-size-current));
	font-weight: var(--mod-breadcrumbs-font-weight-current, var(--spectrum-breadcrumbs-font-weight-current));

	.spectrum-Breadcrumbs-itemSeparator {
		display: none;
	}
}

> .spectrum-ActionButton {
	margin-inline: var(--mod-breadcrumbs-action-button-spacing-inline, var(--spectrum-breadcrumbs-action-button-spacing-inline));
	margin-block: var(--mod-breadcrumbs-action-button-spacing-block, var(--spectrum-breadcrumbs-action-button-spacing-block));

	color: var(--highcontrast-breadcrumbs-action-button-color, var(--mod-breadcrumbs-action-button-color, var(--spectrum-breadcrumbs-action-button-color)));

	&:disabled {
		color: var(--highcontrast-breadcrumbs-action-button-color-disabled, var(--mod-breadcrumbs-action-button-color-disabled, var(--spectrum-breadcrumbs-action-button-color-disabled)));
	}
}

&[href],
	&[tabindex="0"] {
		cursor: pointer;

		&:hover,
		&:focus-visible {
			text-decoration: underline;
			text-decoration-thickness: var(--mod-breadcrumbs-text-decoration-thickness, var(--spectrum-breadcrumbs-text-decoration-thickness));
			text-underline-offset: var(--mod-breadcrumbs-text-decoration-gap, var(--spectrum-breadcrumbs-text-decoration-gap));
		}
	}

&:disabled,
	&.is-disabled,
	&[pending],
	&.is-pending {
		background-color: var(--highcontrast-button-background-color-disabled, var(--mod-button-background-color-disabled, var(--spectrum-button-background-color-disabled)));
		border-color: var(--highcontrast-button-border-color-disabled, var(--mod-button-border-color-disabled, var(--spectrum-button-border-color-disabled)));
		color: var(--highcontrast-button-content-color-disabled, var(--mod-button-content-color-disabled, var(--spectrum-button-content-color-disabled)));
	}

&.spectrum-Button--iconOnly {
	min-inline-size: unset;
	padding: calc(var(--mod-button-edge-to-visual-only, var(--spectrum-button-edge-to-visual-only)) - var(--mod-button-border-width, var(--spectrum-button-border-width)));
	border-radius: 50%;

	.spectrum-Icon {
		align-self: center;
		margin-inline-start: 0;
		margin-block-start: 0;
	}

	&::after {
		border-radius: 50%;
	}
}

&::after {
	content: "";
	block-size: 100%;
	inline-size: 100%;
	position: absolute;
	inset-inline-start: 0;
	inset-inline-end: 0;
	inset-block-start: 0;
	border-style: solid;
	border-color: transparent;
	border-width: 0;
	border-radius: var(--spectrum-card-corner-radius);
	margin-block-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
	margin-inline-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
}

&::after {
	content: "";
	block-size: 100%;
	inline-size: 100%;
	position: absolute;
	inset-inline-start: 0;
	inset-inline-end: 0;
	inset-block-start: 0;
	border-style: solid;
	border-color: transparent;
	border-width: 0;
	border-radius: calc(var(--spectrum-card-corner-radius) + var(--spectrum-card-focus-indicator-width));
	margin-block-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
	margin-inline-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
}

@container style(--system: legacy) {
	.spectrum-ClearButton {
		&.spectrum-ClearButton--staticWhite {
			--spectrum-clear-button-background-color-hover: var(--spectrum-transparent-white-300);
			--spectrum-clear-button-background-color-down: var(--spectrum-transparent-white-400);
			--spectrum-clear-button-background-color-key-focus: var(--spectrum-transparent-white-300);
		}
	}
}

&::after {
	content: "";
	inset-inline: calc(50% - calc(var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width)) / 2));
	inset-block: calc(50% - calc(var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width)) / 2));
	position: absolute;
	display: block;
	inline-size: var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width));
	block-size: var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width));
	border-radius: var(--mod-colorhandle-hitarea-border-radius, 100%);
}

%spectrum-overlay {
	pointer-events: none;
	visibility: hidden;
	opacity: 0;
	transition:
		transform var(--mod-overlay-animation-duration, var(--spectrum-animation-duration-100, 130ms)) ease-in-out,
		opacity var(--mod-overlay-animation-duration, var(--spectrum-animation-duration-100, 130ms)) ease-in-out,
		visibility 0ms linear var(--mod-overlay-animation-duration, var(--spectrum-animation-duration-100, 130ms));
}

@media (forced-colors: active) {
	.spectrum-DatePicker {
		--highcontrast-datepicker-dash-color: CanvasText;
		--highcontrast-datepicker-focus-ring-color: Highlight;
		--highcontrast-datepicker-pickerbutton-border-color: Highlight;

		&.is-disabled {
			--highcontrast-datepicker-dash-color: GrayText;
		}

		&.spectrum-DatePicker--quiet.is-invalid {
			--highcontrast-datepicker-pickerbutton-border-color: Highlight;
		}
	}
}

&::after {
	position: absolute;
	inset: 0;
	margin: calc(-1 * var(--mod-floating-action-button-focus-ring-gap, var(--spectrum-focus-indicator-gap)));
	box-shadow: 0 0 0 var(--mod-floating-action-button-focus-ring-width, var(--spectrum-focus-indicator-thickness)) var(--mod-afloating-action-button-focus-ring-color, var(--spectrum-focus-indicator-color));
	border-radius: var(--mod-floating-action-button-border-radius, 50%);
	pointer-events: none;
	content: "";
}

&.spectrum-InfieldButton--top,
	&.spectrum-InfieldButton--bottom {
		--mod-infield-button-width: var(--mod-infield-button-width-stacked, var(--spectrum-in-field-button-width-stacked-medium));

		&.spectrum-InfieldButton--sizeS {
			--mod-infield-button-width: var(--mod-infield-button-width-stacked, var(--spectrum-in-field-button-width-stacked-small));
		}

		&.spectrum-InfieldButton--sizeL {
			--mod-infield-button-width: var(--mod-infield-button-width-stacked, var(--spectrum-in-field-button-width-stacked-large));
		}

		&.spectrum-InfieldButton--sizeXL {
			--mod-infield-button-width: var(--mod-infield-button-width-stacked, var(--spectrum-in-field-button-width-stacked-extra-large));
		}
	}

@media (forced-colors: active) {
	.spectrum-InfieldButton {
		--highcontrast-infield-button-border-color: ButtonText;
		--highcontrast-infield-button-border-color-active: Highlight;

		&:disabled {
			--highcontrast-infield-button-border-color: inherit;
		}

		&:not(:disabled):hover,
		&:not(:disabled):active,
		&:not(:disabled):focus-visible {
			--highcontrast-infield-button-border-color: var(--highcontrast-infield-button-border-color-active);
		}
	}
}

@container style(--system: legacy) {
	.spectrum-InfieldButton {
		--spectrum-infield-button-background-color: var(--spectrum-gray-75);
		--spectrum-infield-button-background-color-hover: var(--spectrum-gray-200);
		--spectrum-infield-button-background-color-down: var(--spectrum-gray-300);
		--spectrum-infield-button-background-color-key-focus: var(--spectrum-gray-200);

		&:disabled {
			--spectrum-infield-button-border-color: var(--spectrum-gray-200);
		}
	}
}

@media only screen and (device-width <= 400px), only screen and (device-height <= 350px) {
	.spectrum-Modal--responsive {
		inline-size: 100%;
		block-size: 100%;
		max-inline-size: 100%;
		max-block-size: 100%;
		border-radius: 0;
	}

	.spectrum-Modal-wrapper .spectrum-Modal--responsive {
		margin-block-start: 0; /* Prevent the vertical offset bit */
	}
}

@media (forced-colors: active) {
	.spectrum-Steplist {
		--highcontrast-steplist-complete-marker-background-color: CanvasText;
		--highcontrast-steplist-current-marker-color: Highlight;
		--highcontrast-steplist-current-marker-color-key-focus: Highlight;
	}

	@supports (color: SelectedItem) {
		.spectrum-Steplist {
			--highcontrast-steplist-current-marker-color: SelectedItem;
		}
	}
}

&::after {
	content: "";
	position: absolute;
	inset: calc(-2 * var(--mod-swatch-focus-indicator-gap, var(--spectrum-swatch-focus-indicator-gap)));

	opacity: 0;

	border-width: var(--mod-swatch-focus-indicator-thickness, var(--spectrum-swatch-focus-indicator-thickness));
	border-style: solid;
	border-color: var(--highcontrast-swatch-focus-indicator-color, var(--mod-swatch-focus-indicator-color, var(--spectrum-swatch-focus-indicator-color)));
	border-radius: var(--mod-swatch-focus-indicator-border-radius, var(--spectrum-swatch-focus-indicator-border-radius));

	transition: opacity var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-in-out;
}

&:not(.spectrum-Swatch--rectangle) {
	&,
	&::before,
	&::after,
	.spectrum-Swatch-fill,
	.spectrum-Swatch-fill::before,
	&.is-selected .spectrum-Swatch-fill,
	&.is-selected .spectrum-Swatch-fill::before {
		border-radius: 100%;
	}

	&.is-selected .spectrum-Swatch-fill {
		clip-path: circle(calc(50% - (var(--mod-swatch-border-thickness-selected, var(--spectrum-swatch-border-thickness-selected)) * 2)) at 50% 50%);
	}
}

&::after {
	border-radius: calc(calc(var(--mod-switch-control-height, var(--spectrum-switch-control-height)) / 2) + var(--mod-focus-indicator-gap, var(--spectrum-focus-indicator-gap)) * 2);
	content: "";
	display: block;
	position: absolute;
	inset-inline-start: 0;
	inset-inline-end: 0;
	inset-block-end: 0;
	inset-block-start: 0;
	margin: 0;

	transition:
		opacity var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-out,
		margin var(--spectrum-animation-duration-100, var(--spectrum-animation-duration-100)) ease-out;
}

@media (forced-colors: active) {
	.spectrum-Tooltip {
		border: 1px solid transparent;
	}

	.spectrum-Tooltip-tip {
		--highcontrast-tooltip-background-color-default: CanvasText;
		--highcontrast-tooltip-background-color-informative: CanvasText;
		--highcontrast-tooltip-background-color-positive: CanvasText;
		--highcontrast-tooltip-background-color-negative: CanvasText;

		forced-color-adjust: none;
	}
}
